--
-- Name: note_with_versions _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.note_with_versions AS
 SELECT n.id,
    n.author,
    n.author_name,
    n.author_email,
    n.for_student,
    n.date_created,
    n.date_deleted,
    n.deleted_by,
        CASE
            WHEN (n.date_deleted IS NULL) THEN jsonb_agg(jsonb_build_object('id', nv.id, 'content', nv.content, 'dateCreated', nv.date_created, 'versionNumber', nv.version_number) ORDER BY nv.version_number)
            ELSE '[]'::jsonb
        END AS versions,
        CASE
            WHEN (n.date_deleted IS NULL) THEN COALESCE(( SELECT jsonb_agg(jsonb_build_object('id', nt.id, 'name', nt.name, 'color', nt.color) ORDER BY nt.name) AS jsonb_agg
               FROM (public.note_tag_relation ntr
                 JOIN public.note_tag nt ON ((nt.id = ntr.tag_id)))
              WHERE (ntr.note_id = n.id)), '[]'::jsonb)
            ELSE '[]'::jsonb
        END AS tags
   FROM (public.note n
     JOIN public.note_version nv ON ((nv.for_note = n.id)))
  GROUP BY n.id;


--
-- Name: privacy_export_with_docs _RETURN; Type: RULE; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.privacy_export_with_docs AS
 SELECT e.id,
    e.user_id,
    e.student_id,
    e.status,
    e.date_created,
    e.valid_until,
    e.next_request_allowed_at,
    COALESCE(jsonb_agg(jsonb_build_object('id', ed.id, 'date_created', ed.date_created, 'source_name', ed.source_name, 'status', ed.status, 'file_size', ed.file_size, 'downloaded_at', ed.downloaded_at) ORDER BY ed.date_created) FILTER (WHERE (ed.id IS NOT NULL)), '[]'::jsonb) AS documents
   FROM (public.privacy_export e
     LEFT JOIN public.privacy_export_document ed ON ((ed.export_id = e.id)))
  GROUP BY e.id;


